async function execute(k) {
// The k-means model configuration
const options = {
k,
maxIter: 20,
};
// Arguments are: file's path, config, and a
// callback that’s called once the clustering ends
model = ml5.kmeans(csvUrl, options, () => {
console.log('Done :)');
});
}
